/* Hero Section: Full-Width Image with Centered Text */
.hero-section {
    position: relative;
    width: 100%;
    height: 100vh; /* Full viewport height */
    background-image: url('your-hero-image-url.jpg'); /* Replace with your image */
    background-size: cover;
    background-position: center;
    display: flex;
    align-items: center;
    justify-content: center;
}

.hero-section h1 {
    font-size: 3em; /* Large font size for heading */
    color: #ffffff;
    text-shadow: 2px 2px 10px rgba(0, 0, 0, 0.7); /* Add shadow for readability */
    text-align: center;
}

.hero-section a {
    display: inline-block;
    background-color: #0077cc; /* Accent button color */
    color: #fff;
    padding: 15px 30px;
    border-radius: 5px;
    text-transform: uppercase;
    font-weight: bold;
    text-decoration: none;
}

.hero-section a:hover {
    background-color: #005fa3; /* Darker accent color on hover */
}

/* Navigation Bar */
.header {
    position: fixed;
    top: 0;
    width: 100%;
    background-color: rgba(255, 255, 255, 0.9); /* Transparent background */
    box-shadow: 0px 4px 10px rgba(0, 0, 0, 0.1);
}

.header-nav a {
    color: #333333; /* Dark text color */
    font-size: 1.2em;
    text-transform: uppercase;
    padding: 15px 20px;
}

.header-nav a:hover {
    color: #0077cc; /* Accent color for hover */
}

/* Service Grid */
.service-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr); /* Three-column layout */
    grid-gap: 30px;
    margin: 50px 0;
}

.service-item {
    text-align: center;
    padding: 20px;
    border-radius: 10px;
    background-color: #f7f7f7;
    box-shadow: 0px 4px 6px rgba(0, 0, 0, 0.1);
}

.service-item img {
    width: 80px;
    margin-bottom: 15px;
}

.service-item h3 {
    font-size: 1.5em;
    color: #333333;
}

.service-item p {
    color: #666666;
    font-size: 1em;
}

/* Portfolio Section */
.portfolio-gallery {
    display: grid;
    grid-template-columns: repeat(3, 1fr); /* Adjust based on your layout */
    grid-gap: 30px;
}

.portfolio-item {
    border-radius: 10px;
    overflow: hidden;
    box-shadow: 0px 4px 8px rgba(0, 0, 0, 0.1);
}

.portfolio-item img {
    width: 100%;
    transition: transform 0.3s ease;
}

.portfolio-item:hover img {
    transform: scale(1.05); /* Slight zoom on hover */
}

.portfolio-item h4 {
    text-align: center;
    margin-top: 15px;
    font-size: 1.2em;
}

/* Footer */
.footer {
    background-color: #333333;
    color: #ffffff;
    padding: 40px;
    text-align: center;
}

.footer a {
    color: #0077cc;
    text-decoration: none;
}

.footer a:hover {
    color: #ffffff;
}

.footer p {
    font-size: 0.9em;
    margin-top: 20px;
}

/* Mobile Optimization */
@media screen and (max-width: 768px) {
    .service-grid, .portfolio-gallery {
        grid-template-columns: 1fr; /* Stack items vertically on mobile */
    }

    .hero-section h1 {
        font-size: 2em;
    }

    .header-nav a {
        font-size: 1em;
    }
